    // Create a list of edges with their strength and must flag
    let mustEdges: [number, number, number][] = [];
    let optionalEdges: [number, number, number][] = [];

    for (let edge of edges) {
        let [u, v, s, must] = edge;
        if (must === 1) {
            mustEdges.push([u, v, s]);
        } else {
            optionalEdges.push([u, v, s]);
        }
    }

    // Sort must edges by strength (we need them in the spanning tree)
    mustEdges.sort((a, b) => a[2] - b[2]);

    // Sort optional edges by strength (we can upgrade them)
    optionalEdges.sort((a, b) => a[2] - b[2]);

    // Use a Union-Find (Disjoint Set Union) data structure to check connectivity
    class UnionFind {
        parent: number[];
        rank: number[];

        constructor(n: number) {
            this.parent = Array(n).fill(0);
            this.rank = Array(n).fill(0);
            for (let i = 0; i < n; i++) {
                this.parent[i] = i;
            }
        }

        find(x: number): number {
            if (this.parent[x] !== x) {
                this.parent[x] = this.find(this.parent[x]);
            }
            return this.parent[x];
        }

        union(x: number, y: number): boolean {
            const xRoot = this.find(x);
            const yRoot = this.find(y);
            if (xRoot === yRoot) {
                return false; // Already connected
            }
            if (this.rank[xRoot] < this.rank[yRoot]) {
                this.parent[xRoot] = yRoot;
            } else {
                this.parent[yRoot] = xRoot;
                if (this.rank[xRoot] === this.rank[yRoot]) {
                    this.rank[xRoot]++;
                }
            }
            return true;
        }
    }

    const uf = new UnionFind(n);

    // First, add all must edges to the spanning tree
    for (let [u, v, s] of mustEdges) {
        if (uf.union(u, v)) {
            // If the union was successful, the edge is part of the spanning tree
        }
    }

    // Check if all nodes are connected with must edges only
    const root = uf.find(0);
    for (let i = 1; i < n; i++) {
        if (uf.find(i) !== root) {
            return -1; // Not connected, cannot form a spanning tree
        }
    }

    // Now, try to add optional edges to increase the minimum strength
    let minStrength = Infinity;
    let usedK = 0;

    // Sort optional edges by strength (we want to use the ones with higher strength first)
    optionalEdges.sort((a, b) => b[2] - a[2]);

    for (let [u, v, s] of optionalEdges) {
        if (usedK < k) {
            // We can upgrade this edge
            const upgradedStrength = s * 2;
            if (uf.union(u, v)) {
                minStrength = Math.min(minStrength, upgradedStrength);
                usedK++;
            }
        } else {
            // We cannot upgrade this edge anymore
            if (uf.union(u, v)) {
                minStrength = Math.min(minStrength, s);
            }
        }
    }

    // Check if all nodes are connected
    const finalRoot = uf.find(0);
    for (let i = 1; i < n; i++) {
        if (uf.find(i) !== finalRoot) {
            return -1; // Not connected, cannot form a spanning tree
        }
    }

